arguments.new_str:
using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Preserve EF8 discriminator property name so existing documents remain readable
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");
        // Preserve EF8 compound id format ("Blog|1") so existing documents remain accessible
        modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);
        // HasIndex removed — Cosmos DB indexing is managed via the container's indexing policy,
        // not EF Core. In EF Core 9 this call throws InvalidOperationException.
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

arguments.old_str:
class SyncJob
{
    void Run(BlogContext context)
    {
        var blogs = context.Blogs.ToList();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        context.SaveChanges();
    }
}

arguments.new_str:
class SyncJob
{
    // EF Core 9 Cosmos provider no longer supports synchronous I/O —
    // ToList() and SaveChanges() throw. Use async equivalents.
    async Task RunAsync(BlogContext context)
    {
        var blogs = await context.Blogs.ToListAsync();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        await context.SaveChangesAsync();
    }
}

